		templ_7745c5c3_Err = templruntime.WriteString(templ_7745c5c3_Buffer, 4, "</main><!-- Plyr popup --><dialog id=\"player-dialog\"><div class=\"player-header\"><span class=\"player-title\" id=\"player-title\"></span> <button id=\"pip-btn\" class=\"player-close\" onclick=\"togglePiP()\" title=\"Картинка в картинке\" style=\"display:none\"><span class=\"m3-icon\">picture_in_picture</span></button> <button class=\"player-close\" onclick=\"closePlayer()\"><span class=\"m3-icon\">close</span></button></div><video id=\"plyr-video\" playsinline></video></dialog><!-- Log popup --><dialog id=\"log-dialog\"><div class=\"log-header\"><span class=\"log-title\" id=\"log-dialog-title\">Лог скачивания</span> <button class=\"player-close\" onclick=\"closeLog()\"><span class=\"m3-icon\">close</span></button></div><pre id=\"log-content\"></pre></dialog><script>\n\t\t\t\t// ── Plyr ──\n\t\t\t\tvar plyrInstance;\n\t\t\t\tdocument.addEventListener('DOMContentLoaded', function() {\n\t\t\t\t\tplyrInstance = new Plyr('#plyr-video', {\n\t\t\t\t\t\tcontrols: ['play-large','play','progress','current-time','duration','mute','volume','fullscreen'],\n\t\t\t\t\t\tratio: '16:9',\n\t\t\t\t\t});\n\n\t\t\t\t\t// ── PiP (Picture-in-Picture) ──\n\t\t\t\t\tvar pipBtn = document.getElementById('pip-btn');\n\t\t\t\t\tvar video  = document.getElementById('plyr-video');\n\t\t\t\t\tif (document.pictureInPictureEnabled) {\n\t\t\t\t\t\tpipBtn.style.display = '';\n\t\t\t\t\t}\n\t\t\t\t\tvideo.addEventListener('enterpictureinpicture', function() {\n\t\t\t\t\t\tpipBtn.querySelector('.m3-icon').textContent = 'picture_in_picture_alt';\n\t\t\t\t\t});\n\t\t\t\t\tvideo.addEventListener('leavepictureinpicture', function() {\n\t\t\t\t\t\tpipBtn.querySelector('.m3-icon').textContent = 'picture_in_picture';\n\t\t\t\t\t\t// Если диалог уже закрыт — паузим видео\n\t\t\t\t\t\tif (!document.getElementById('player-dialog').open) plyrInstance.pause();\n\t\t\t\t\t});\n\n\t\t\t\t\t// ── Авто-полноэкранный режим при повороте ──\n\t\t\t\t\tfunction _onOrientationChange() {\n\t\t\t\t\t\tif (!document.getElementById('player-dialog').open) return;\n\t\t\t\t\t\t// Небольшая задержка — браузер обновляет размеры после события\n\t\t\t\t\t\tsetTimeout(function() {\n\t\t\t\t\t\t\tvar isLandscape = screen.orientation\n\t\t\t\t\t\t\t\t? screen.orientation.type.includes('landscape')\n\t\t\t\t\t\t\t\t: Math.abs(window.orientation || 0) === 90;\n\t\t\t\t\t\t\tif (isLandscape) {\n\t\t\t\t\t\t\t\tif (!plyrInstance.fullscreen.active) plyrInstance.fullscreen.enter();\n\t\t\t\t\t\t\t} else {\n\t\t\t\t\t\t\t\tif (plyrInstance.fullscreen.active) plyrInstance.fullscreen.exit();\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}, 150);\n\t\t\t\t\t}\n\t\t\t\t\tif (screen.orientation) {\n\t\t\t\t\t\tscreen.orientation.addEventListener('change', _onOrientationChange);\n\t\t\t\t\t} else {\n\t\t\t\t\t\twindow.addEventListener('orientationchange', _onOrientationChange);\n\t\t\t\t\t}\n\t\t\t\t});\n\n\t\t\t\tfunction togglePiP() {\n\t\t\t\t\tvar video = document.getElementById('plyr-video');\n\t\t\t\t\tif (document.pictureInPictureElement) {\n\t\t\t\t\t\tdocument.exitPictureInPicture();\n\t\t\t\t\t} else if (document.pictureInPictureEnabled) {\n\t\t\t\t\t\tvideo.requestPictureInPicture().catch(function(){});\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\tfunction openPlayer(src, title) {\n\t\t\t\t\tdocument.getElementById('player-title').textContent = title || src;\n\t\t\t\t\tplyrInstance.source = { type: 'video', sources: [{ src: src, type: 'video/mp4' }] };\n\t\t\t\t\tdocument.getElementById('player-dialog').showModal();\n\t\t\t\t\tplyrInstance.play();\n\t\t\t\t}\n\t\t\t\tfunction closePlayer() {\n\t\t\t\t\t// Если активен PiP — не паузим (видео продолжает играть в мини-окне)\n\t\t\t\t\tif (!document.pictureInPictureElement) plyrInstance.pause();\n\t\t\t\t\tdocument.getElementById('player-dialog').close();\n\t\t\t\t}\n\t\t\t\tdocument.getElementById('player-dialog').addEventListener('click', function(e) {\n\t\t\t\t\tif (e.target === this) closePlayer();\n\t\t\t\t});\n\n\t\t\t\t// ── Log dialog ──\n\t\t\t\tfunction openLog(jobID, title) {\n\t\t\t\t\tdocument.getElementById('log-dialog-title').textContent = (title || 'Лог скачивания') + ' — лог';\n\t\t\t\t\tvar pre = document.getElementById('log-content');\n\t\t\t\t\tpre.textContent = 'Загрузка…';\n\t\t\t\t\tdocument.getElementById('log-dialog').showModal();\n\t\t\t\t\tfetch('jobs/' + jobID + '/log')\n\t\t\t\t\t\t.then(function(r) { return r.ok ? r.text() : Promise.reject('Лог недоступен'); })\n\t\t\t\t\t\t.then(function(t) { pre.textContent = t || '(пусто)'; })\n\t\t\t\t\t\t.catch(function(e) { pre.textContent = String(e); });\n\t\t\t\t}\n\t\t\t\tfunction closeLog() {\n\t\t\t\t\tdocument.getElementById('log-dialog').close();\n\t\t\t\t}\n\t\t\t\tdocument.getElementById('log-dialog').addEventListener('click', function(e) {\n\t\t\t\t\tif (e.target === this) closeLog();\n\t\t\t\t});\n\n\t\t\t\t// ── File ops ──\n\t\t\t\tfunction renameFile(id, newName) {\n\t\t\t\t\tfetch('files/' + id, {\n\t\t\t\t\t\tmethod: 'PATCH',\n\t\t\t\t\t\theaders: {'Content-Type': 'application/json'},\n\t\t\t\t\t\tbody: JSON.stringify({name: newName}),\n\t\t\t\t\t}).then(function() {\n\t\t\t\t\t\thtmx.ajax('GET', 'media/list', {target: '#media-inner', swap: 'outerHTML'});\n\t\t\t\t\t});\n\t\t\t\t}\n\t\t\t\tfunction renamePrompt(id, name) {\n\t\t\t\t\tvar n = prompt('Новое имя:', name);\n\t\t\t\t\tif (n && n.trim()) renameFile(id, n.trim());\n\t\t\t\t}\n\t\t\t\tfunction copyPresigned(id, btn) {\n\t\t\t\t\tfetch('files/' + id + '/link', {method: 'POST'})\n\t\t\t\t\t\t.then(function(r) { return r.json(); })\n\t\t\t\t\t\t.then(function(d) {\n\t\t\t\t\t\t\tnavigator.clipboard.writeText(d.url).then(function() {\n\t\t\t\t\t\t\t\tvar icon = btn.querySelector('.m3-icon');\n\t\t\t\t\t\t\t\tif (icon) { icon.textContent = 'check'; setTimeout(function() { icon.textContent = 'link'; }, 1500); }\n\t\t\t\t\t\t\t});\n\t\t\t\t\t\t});\n\t\t\t\t}\n\t\t\t\tfunction copyOriginalURL(url) {\n\t\t\t\t\tnavigator.clipboard.writeText(url);\n\t\t\t\t}\n\n\t\t\t\t// ── Tags ──\n\t\t\t\tfunction addTag(jobID) {\n\t\t\t\t\tvar n = prompt('Новый тег:');\n\t\t\t\t\tif (!n || !n.trim()) return;\n\t\t\t\t\tfetch('jobs/' + jobID + '/tags', {\n\t\t\t\t\t\tmethod: 'POST',\n\t\t\t\t\t\theaders: {'Content-Type': 'application/json'},\n\t\t\t\t\t\tbody: JSON.stringify({name: n.trim()}),\n\t\t\t\t\t}).then(function() {\n\t\t\t\t\t\thtmx.ajax('GET', 'media/list', {target: '#media-inner', swap: 'outerHTML'});\n\t\t\t\t\t});\n\t\t\t\t}\n\n\t\t\t\t// ── Client-side filtering ──\n\t\t\t\tvar _activeTag = null;\n\n\t\t\t\tvar _statusLabels = {\n\t\t\t\t\t'checking':'проверка…','pending':'ожидание','running':'скачивается',\n\t\t\t\t\t'retrying':'повтор','done':'готово','failed':'ошибка',\n\t\t\t\t\t'missing':'отсутствует','deleted':'удалён','cancelled':'отменено',\n\t\t\t\t\t'hidden':'скрытые','imported':'импортированы'\n\t\t\t\t};\n\n\t\t\t\t// Активировать статус-фильтр (вызывается из чипа внутри строки).\n\t\t\t\tfunction activateStatusFilter(tag) {\n\t\t\t\t\tvar existing = document.querySelector('#status-chips [data-tag=\"' + tag + '\"]');\n\t\t\t\t\tif (existing) { toggleTagFilter(existing); } else { setActiveTag(tag); applyFilters(); }\n\t\t\t\t}\n\n\t\t\t\tfunction toggleTagFilter(btn) {\n\t\t\t\t\tvar tag = btn.dataset.tag;\n\t\t\t\t\tif (_activeTag === tag) {\n\t\t\t\t\t\tsetActiveTag(null);\n\t\t\t\t\t} else {\n\t\t\t\t\t\tsetActiveTag(tag);\n\t\t\t\t\t}\n\t\t\t\t\tapplyFilters();\n\t\t\t\t}\n\n\t\t\t\tfunction setActiveTag(tag) {\n\t\t\t\t\t_activeTag = tag;\n\t\t\t\t\t// Снимаем active со всех фильтр-чипов.\n\t\t\t\t\tdocument.querySelectorAll('.tag-filter-row .m3-chip, #status-chips .m3-chip').forEach(function(b) {\n\t\t\t\t\t\tb.classList.toggle('active', b.dataset.tag === tag);\n\t\t\t\t\t});\n\t\t\t\t}\n\n\t\t\t\tfunction applyFilters() {\n\t\t\t\t\tvar q = (document.getElementById('media-search') || {value:''}).value.toLowerCase();\n\t\t\t\t\tvar showHidden = _activeTag === 'hidden';\n\t\t\t\t\tdocument.querySelectorAll('.media-row').forEach(function(row) {\n\t\t\t\t\t\tvar isHiddenRow = row.classList.contains('is-hidden');\n\t\t\t\t\t\t// Режим «скрытые»: показываем только скрытые строки.\n\t\t\t\t\t\tif (showHidden) { row.style.display = isHiddenRow ? '' : 'none'; return; }\n\t\t\t\t\t\t// Обычный режим: скрытые строки не видны.\n\t\t\t\t\t\tif (isHiddenRow) { row.style.display = 'none'; return; }\n\n\t\t\t\t\t\tvar text = (row.dataset.title + ' ' + row.dataset.url + ' ' + row.dataset.domain).toLowerCase();\n\t\t\t\t\t\tvar tags = (row.dataset.tags || '').split(',');\n\t\t\t\t\t\tvar matchSearch = !q || text.includes(q) || tags.some(function(t){ return t.toLowerCase().includes(q); });\n\t\t\t\t\t\tvar matchTag = !_activeTag || tags.indexOf(_activeTag) >= 0;\n\t\t\t\t\t\trow.style.display = (matchSearch && matchTag) ? '' : 'none';\n\t\t\t\t\t});\n\t\t\t\t}\n\n\t\t\t\t// Строим чипы статусов из текущих данных.\n\t\t\t\tfunction rebuildStatusChips() {\n\t\t\t\t\tvar seen = {}, order = [];\n\t\t\t\t\tdocument.querySelectorAll('.media-row').forEach(function(row) {\n\t\t\t\t\t\tvar s = (row.dataset.tags || '').split(',')[0];\n\t\t\t\t\t\tif (s && !seen[s]) { seen[s] = true; order.push(s); }\n\t\t\t\t\t});\n\t\t\t\t\t// «скрытые» всегда последним.\n\t\t\t\t\tif (!seen['hidden']) order.push('hidden');\n\n\t\t\t\t\tvar container = document.getElementById('status-chips');\n\t\t\t\t\tif (!container) return;\n\t\t\t\t\tcontainer.innerHTML = '';\n\t\t\t\t\torder.forEach(function(s) {\n\t\t\t\t\t\tvar btn = document.createElement('button');\n\t\t\t\t\t\tbtn.className = 'm3-chip' + (s === 'hidden' ? ' m3-chip-hidden' : '');\n\t\t\t\t\t\tbtn.dataset.tag = s;\n\t\t\t\t\t\tbtn.textContent = _statusLabels[s] || s;\n\t\t\t\t\t\tif (_activeTag === s) btn.classList.add('active');\n\t\t\t\t\t\tbtn.addEventListener('click', function() { toggleTagFilter(this); });\n\t\t\t\t\t\tcontainer.appendChild(btn);\n\t\t\t\t\t});\n\t\t\t\t}\n\n\t\t\t\t// Переприменяем фильтр и пересобираем чипы после HTMX-обновления.\n\t\t\t\tdocument.body.addEventListener('htmx:afterSwap', function(e) {\n\t\t\t\t\tif (e.detail.target && e.detail.target.id === 'media-inner') {\n\t\t\t\t\t\trebuildStatusChips();\n\t\t\t\t\t\tapplyFilters();\n\t\t\t\t\t}\n\t\t\t\t});\n\t\t\t\t// Первый запуск.\n\t\t\t\tdocument.addEventListener('DOMContentLoaded', function() {\n\t\t\t\t\trebuildStatusChips();\n\t\t\t\t\tapplyFilters();\n\t\t\t\t});\n\t\t\t</script></body></html>")
